function ModelFastDreamTrip:InitDreamTripConfigRef()
	local initDreamTripConfigRef = self._initDreamTripConfigRef
	if not initDreamTripConfigRef then
		initDreamTripConfigRef = {}
		self._initDreamTripConfigRef = initDreamTripConfigRef
	end

	local configRef = GameTable.SailingConfigRef
	for k,v in pairs(configRef) do
		initDreamTripConfigRef[k] = v
	end

	local playStar = string.split(configRef.playStar,"=")
	initDreamTripConfigRef.playStarList = {
		itemType = tonumber(playStar[1]),
		itemId = tonumber(playStar[2]),
		itemNum = tonumber(playStar[3])
	}
end

function ModelFastDreamTrip:InitDreamTripMapRef()
	local weekOpenTimeList = {}
	local weekOpenTimeStrList = {}
	local weekOpenTimeMap = {}
	local temp
	for k,v in pairs(GameTable.SailingMapRef) do
		if not string.isempty(v.time) then
			temp = string.split(v.time,",")
			for _i,_v in ipairs(temp) do
				_v = tonumber(_v)
				weekOpenTimeMap[_v] = true
				table.insert(weekOpenTimeList,_v)
			end
			table.insert(weekOpenTimeStrList,{
				str = string.replace("每周#a1#开放#a2#地图",v.time,ccLngText(v.name)),
				sort = k
			})
		end
	end
	table.sort(weekOpenTimeList,function(a,b) return a < b end)
	table.sort(weekOpenTimeStrList,function(a,b) return a.sort < b.sort end)

	local strTips = {}
	for i,v in ipairs(weekOpenTimeStrList) do
		table.insert(strTips,v.str)
	end
	self._weekOpenTimeStr = table.concat(strTips,",")
	self._weekOpenTimeStrList = weekOpenTimeStrList
	self._weekOpenTimeList = weekOpenTimeList
	self._weekOpenTimeMap = weekOpenTimeMap
end

function ModelFastDreamTrip:InitDreamTripRewardRef()
	local initDreamTripRewardRef = self._initDreamTripRewardRef
	if not initDreamTripRewardRef then
		initDreamTripRewardRef = {}
		self._initDreamTripRewardRef = initDreamTripRewardRef
	end

	local initRewardGroupList = self._initRewardGroupList
	if not initRewardGroupList then
		initRewardGroupList = {}
		self._initRewardGroupList = initRewardGroupList
	end

	local robberAwardList = {}
	local robberMoveAwardList = {}


	local robberAward = tonumber(self:GetConfigByKey("robberAward"))
	local robberMoveAward = tonumber(self:GetConfigByKey("robberMoveAward"))

	local rewardGroup,levelMin,levelMax,location,weight
	for k,v in pairs(GameTable.SailingRewardRef) do
		rewardGroup = v.rewardGroup
		levelMin = v.levelMin
		levelMax = v.levelMax
		location = v.location
		weight = v.weight

		local info = {
			refId = k,
			rewardGroup = rewardGroup,
			levelMin = levelMin,
			levelMax = levelMax,
			location = location,
			weight = weight,
		}
		initDreamTripRewardRef[k] = info

		local rewardList = {}
		local reward = string.split(v.reward,",")
		for idx,val in ipairs(reward) do
			val = string.split(val,"=")
			table.insert(rewardList,{
				itemType = tonumber(val[1]),
				itemId = tonumber(val[2]),
				itemNum = tonumber(val[3]),
			})
		end
		info.rewardList = rewardList

		local rewardGroupInfoList = initRewardGroupList[rewardGroup]
		if not rewardGroupInfoList then
			rewardGroupInfoList = {}
			initRewardGroupList[rewardGroup] = rewardGroupInfoList
		end
		table.insert(rewardGroupInfoList,{
			refId = k,
			levelMin = levelMin,
			levelMax = levelMax,
			rewardList = rewardList,
			location = location,
			weight = weight,
			mapLv = v.mapLv
		})

		if rewardGroup == robberAward then
			local robberAwardInfo = {
				levelMin = levelMin,
				levelMax = levelMax,
				rewardList = rewardList,
				weight = weight,
			}
			robberAwardList[k] = robberAwardInfo
		end
		if rewardGroup == robberMoveAward then
			local robberMoveAwardInfo = {
				levelMin = levelMin,
				levelMax = levelMax,
				rewardList = rewardList,
				weight = weight,
			}
			robberMoveAwardList[k] = robberMoveAwardInfo
		end
	end

	self._robberAwardList = robberAwardList
	self._robberMoveAwardList = robberMoveAwardList
end

function ModelFastDreamTrip:InitDreamTripTextRef()
	local initDreamTripTextRef = self._initDreamTripTextRef
	if not initDreamTripTextRef then
		initDreamTripTextRef = {}
		self._initDreamTripTextRef = initDreamTripTextRef
	end
	for k,v in pairs(GameTable.SailingTextRef) do
		local info = {
			refId = k,
			type = v.type,
			num = v.num,
			right = v.right,
			dec = v.dec,
			answer = v.answer,
		}
		initDreamTripTextRef[k] = info
		local answerList = {}
		local answer = string.split(ccLngText(v.answer),"|")
		for idx,val in ipairs(answer) do
			table.insert(answerList,val)
		end
		info.answerList = answerList
	end
end

function ModelFastDreamTrip:InitDreamTripMapLevelRef()
	local initDreamTripMapLevelRef = {}
	local map
	for k,v in pairs(GameTable.SailingMapLevelRef) do
		map = v.map
		local initDreamTripMapLevel = initDreamTripMapLevelRef[map]
		if not initDreamTripMapLevel then
			initDreamTripMapLevel = {}
			initDreamTripMapLevelRef[map] = initDreamTripMapLevel
		end
		table.insert(initDreamTripMapLevel,v)
	end

	for k,v in pairs(initDreamTripMapLevelRef) do
		table.sort(v,function(a,b) return a.level > b.level end)
	end
	self._initDreamTripMapLevelRef = initDreamTripMapLevelRef
end

function ModelFastDreamTrip:InitDreamTripEventRef()
	--- 解析事件数据 Map 结构
	local paramEventPointDataMap = {}

	--- 预显示岔路格子
	local paramEventPointForkShowMap = {}

	local paramEventPointByEventRefIdMap = {}

	local map,startIdx,endIdx
	for k,v in pairs(GameTable.SailingEventRef) do
		if v.type == ModelFastDreamTrip.EVENT_TYPE_FORK then
			map = v.map
			local paramEventPointMap = paramEventPointDataMap[map]
			if not paramEventPointMap then
				paramEventPointMap = {}
				paramEventPointDataMap[map] = paramEventPointMap
			end

			local paramEventPointByEventRefIdData = paramEventPointByEventRefIdMap[map]
			if not paramEventPointByEventRefIdData then
				paramEventPointByEventRefIdData = {}
				paramEventPointByEventRefIdMap[map] = paramEventPointByEventRefIdData
			end

			local paramEventPointForkShows = paramEventPointForkShowMap[map]
			if not paramEventPointForkShows then
				paramEventPointForkShows = {}
				paramEventPointForkShowMap[map] = paramEventPointForkShows
			end

			local mapData = {}
			local parameter = string.split(v.parameter,",")
			for idx,val in ipairs(parameter) do
				val = string.split(val,"=")
				startIdx = tonumber(val[2])
				endIdx = tonumber(val[3])
				local tar = 1
				for sIdx = startIdx,endIdx do
					mapData[sIdx] = ModelFastDreamTrip.MAP_POINT_FORK
					if tar <= ModelFastDreamTrip.FORK_TARGET_SHOW_NUM then
						paramEventPointForkShows[sIdx] = true
						tar = tar + 1
					end
					paramEventPointByEventRefIdData[sIdx] = k
				end
			end
			paramEventPointMap[k] = mapData
		end
	end
	self._paramEventPointDataMap = paramEventPointDataMap
	self._paramEventPointForkShowMap = paramEventPointForkShowMap
	self._paramEventPointByEventRefIdMap = paramEventPointByEventRefIdMap
end
