function ModelFastDreamTrip:GetCameraScopeByMapId(mapId)
	mapId = mapId or self:GetDreamTripMapId()
	local cameraInfo = self._initCameraScope[mapId]
	if not cameraInfo then
		local themeCfg = self:GetMapRefByMapId(mapId)
		if themeCfg then
			cameraInfo = {}
			local cameraScope = string.split(themeCfg.cameraScope,";")
			for i,v in ipairs(cameraScope) do
				v = string.split(v,",")
				table.insert(cameraInfo,{
					x = tonumber(v[1]),y = tonumber(v[2])
				})
			end
		else
			cameraInfo = {}
			local cameraScope = string.split("-6.40,6.40;-7.1,7.1",";")
			for i,v in ipairs(cameraScope) do
				v = string.split(v,",")
				table.insert(cameraInfo,{
					x = tonumber(v[1]),y = tonumber(v[2])
				})
			end
		end
	end
	return cameraInfo[1],cameraInfo[2]
end

