function ModelFastDreamTrip:GetDreamTripRewardListByGroup(rewardGroup,ingroeLvLimit)
	ingroeLvLimit = ingroeLvLimit and true or false
	local initRewardGroupList = self._initRewardGroupList
	if not initRewardGroupList then return {} end

	local rewardGroupList = initRewardGroupList[rewardGroup]
	if not rewardGroupList then return {} end

	local mapLevel = self:GetDreamTripMapLevel() or 1
	local list = {}
	local rewardList
	local refId,location,weight
	for i,v in ipairs(rewardGroupList) do
		rewardList = v.rewardList or {}
		refId = v.refId
		location = v.location
		weight = v.weight
		if ingroeLvLimit then
			for idx,val in ipairs(rewardList) do
				table.insert(list,{
					refId = refId,
					location = location,
					weight = weight,
					itemType = val.itemType,
					itemId = val.itemId,
					itemNum = val.itemNum,
				})
			end
		else
			if v.mapLv == -1 then
				for idx,val in ipairs(rewardList) do
					table.insert(list,{
						refId = refId,
						location = location,
						weight = weight,
						itemType = val.itemType,
						itemId = val.itemId,
						itemNum = val.itemNum,
					})
				end
			elseif mapLevel == v.mapLv then
				for idx,val in ipairs(rewardList) do
					table.insert(list,{
						refId = refId,
						location = location,
						weight = weight,
						itemType = val.itemType,
						itemId = val.itemId,
						itemNum = val.itemNum,
					})
				end
			end
		end
	end
	return list
end

