function ModelFastDreamTrip:GetForkroadParameter(eventRefId)
	local forkroadParameterList = self._forkroadParameterList
	if not forkroadParameterList then
		forkroadParameterList = {}
		self._forkroadParameterList = forkroadParameterList
	end
	local data = forkroadParameterList[eventRefId]
	if not data then
		local eventRef = self:GetDreamTripEventRefByRefId(eventRefId)
		if eventRef then
			local parameters = string.split(eventRef.parameter,",")
			if #parameters > 0 then
				data = {}
				for i,v in ipairs(parameters) do
					v = string.split(v,"=")
					table.insert(data,{
						--- 路线id，和服务端交互
						direType = tonumber(v[1]),
						--- 开始的位置
						gridStartIndex = tonumber(v[2]),
						--- 结束的位置
						gridEndIndex = tonumber(v[3]),
						--- 岔路汇合点
						gridLinkIndex = tonumber(v[4])
					})
				end
				forkroadParameterList[eventRefId] = data
			end
		end
	end
	return data
end

