--- 梦境之旅信息请求
function ModelFastDreamTrip:OnDreamTripInfoResp(pb,ret)
	self:InitDreamTripInfo(pb.info)
end

--- 摇骰子请求
function ModelFastDreamTrip:OnDreamTripRollResp(pb,ret)
	gLGpManager:FindFastDreamTripGp():SetRollFsmState()

	self._isRollRun = true

	self._rollNum = pb.roll


	--[[--- 黄金地图：位置移动修改为 DreamTripStartEventResp 协议通知
	if self:CheckCurMapIsDice2() then return end

	local curIndex = self:GetDreamTripIndex()
	local lastIndex = pb.lastIndex
	local roll = pb.roll
	if not roll or roll < 1 then return end

	--- 协议字段废弃
	--self:InitDreamTripInfo(pb.info)

	local state = pb.state
	local moveEndIdx = self:GetDreamTripIndex() + roll

	if curIndex == moveEndIdx then
		printInfoNR2("梦境之旅：","位置相同，不移动")
		return
	end

	self:SetDreamTripIndex(moveEndIdx)

	local lastInFork,lastInForkData = self:CheckCurPointInFork(lastIndex)
	local curInFork,curInForkData = self:CheckCurPointInFork(moveEndIdx)
	local isInFork = lastInFork or curInFork

	if isInFork then
		printInfoNR2("梦境之旅：","岔路处理")
		local forkMoveState,moveFunc = self:_DisposeForkRoll(pb,{
			lastInFork = lastInFork,
			lastInForkData = lastInForkData,
			curInFork = curInFork,
			curInForkData = curInForkData,
			lastIndex = lastIndex,
			moveEndIdx = moveEndIdx,
		},true)
		if forkMoveState then
			moveFunc()
			return
		end
	end

	printInfoNR2("梦境之旅:",
			string.replace("roll = #a1#,lastIndex = #a2#,moveEndIdx = #a3#",
					roll,lastIndex,moveEndIdx
			)
	)

	if state == ModelFastDreamTrip.ROLL_STATE_NORMAL then
		FireEvent(EventNames.ON_FDT_ROLL_NORMAL,{
			lastIndex = lastIndex,
			roll = roll,
			moveEndIdx = moveEndIdx,
			isSwamp = pb.isSwamp,
			showRollTxt = true,
		})
	elseif state == ModelFastDreamTrip.ROLL_STATE_FASTMV then
	elseif state == ModelFastDreamTrip.ROLL_STATE_FORKMV then
		FireEvent(EventNames.ON_FDT_ROLL_NORMAL,{
			lastIndex = lastIndex,
			roll = roll,
			moveEndIdx = moveEndIdx,
			isSwamp = pb.isSwamp,
			showRollTxt = true,
		})
	end]]
end

function ModelFastDreamTrip:_DisposeForkRoll(pb,data,showRollTxt)
	--- 起点数据
	local lastInFork = data.lastInFork
	local lastInForkData = data.lastInForkData

	local curInFork = data.curInFork
	local curInForkData = data.curInForkData

	local lastIndex = data.lastIndex
	local moveEndIdx = data.moveEndIdx

	local pointsList = {}

	if lastInFork then
		local lastEventRefId = lastInForkData.eventRefId
		if curInFork then
			local curEventRefId = curInForkData.eventRefId
			local isSameFork = lastEventRefId == curEventRefId
			--- 结束点在岔路内
			if isSameFork then
				local gridIndex = curInForkData.gridIndex
				local gridEndIndex = curInForkData.gridEndIndex
				for idx = gridIndex,gridEndIndex do
					if idx > lastIndex and idx <= moveEndIdx then
						table.insert(pointsList,idx)
					end
				end
			else
				printInfoNR2("梦境之旅：","暂未开发，从一条岔路进入另外一条岔路")
			end
		else
			--- 结束点在外面
			local gridIndex = lastInForkData.gridIndex
			local gridEndIndex = lastInForkData.gridEndIndex
			for idx = gridIndex,gridEndIndex do
				if idx > lastIndex then
					table.insert(pointsList,idx)
				end
			end
			local gridLinkIndex = lastInForkData.gridLinkIndex
			if gridLinkIndex then
				table.insert(pointsList,gridLinkIndex)
				if moveEndIdx > gridLinkIndex then
					for i = gridLinkIndex + 1,moveEndIdx do
						table.insert(pointsList,i)
					end
				end
			end
		end
	else
		if curInFork then
			local gridIndex = curInForkData.gridIndex
			printInfoNR2("梦境之旅：","起点是岔路点，直接跳到下一个点到终点，gridIndex = " ..
					gridIndex .. ",curInForkData.gridEndIndex = " ..
					curInForkData.gridEndIndex .. ",moveEndIdx = " .. moveEndIdx)
			for i = gridIndex,moveEndIdx do
				table.insert(pointsList,i)
			end
		else
			printInfoNR2("梦境之旅：","啥也不是")
		end
	end
	if #pointsList < 1 then return false end

	local isFlight = data.isFlight

	local isAutoGet = data.isAutoGet
	local playerIndex = data.playerIndex
	local moveFunc
	if isAutoGet then
		moveFunc = function()
			FireEvent(EventNames.ON_FDT_EVENT_FORKMP,{
				pointsList = pointsList,
				roll = self._rollNum or #pointsList,
				isSwamp = 0,
				isFlight = isFlight,
				moveFinishCb = function()
					if playerIndex and playerIndex > 0 then
						self:SetDreamTripIndex(playerIndex)
					end
				end
			})
		end
	else
		moveFunc = function()
			FireEvent(EventNames.ON_FDT_FORK_MOVE,{
				pointsList = pointsList,
				isSwamp = 0,
				roll = self._rollNum or #pointsList,
				showRollTxt = showRollTxt,
				isFlight = isFlight,
				moveFinishCb = function()
					if playerIndex and playerIndex > 0 then
						self:SetDreamTripIndex(playerIndex)
					end
				end
			})
		end
	end


	return true,moveFunc
end

--- 开始事件请求
function ModelFastDreamTrip:OnDreamTripStartEventResp(pb,ret)
 	local flight = pb.flight or 0
	local isFlight = flight == 1

	-- 记录完成事件 Map
	local recordFinishMap = {}
	-- 记录完成事件类型 Map
	local recordFinishEventTypeMap = {}
	local endInfo = pb.endInfo
	local rEventType
	local hasFinishChange = false
	local isFlightEnd = false
	local endInfoLen = #endInfo
	for i,v in ipairs(endInfo) do
		self:UpdateDreamTripEventInfo(v)
		if v.state == 2 then
			recordFinishMap[v.eventId] = v
			rEventType = self:GetDreamTripEventTypeByRefId(v.eventRefId)
			local finishEventTypeList = recordFinishEventTypeMap[rEventType]
			if not finishEventTypeList then
				finishEventTypeList = {}
				recordFinishEventTypeMap[rEventType] = finishEventTypeList
			end
			table.insert(finishEventTypeList,v)

			if not hasFinishChange then hasFinishChange = true end

			if endInfoLen == i and rEventType == ModelFastDreamTrip.EVENT_TYPE_FLIGHT then
				--- 结束是飞行事件，表示全程飞完了，行走
				isFlightEnd = true
			end
		end
	end

	if hasFinishChange then
		self:UpdateDreamTripSuccessIndex()
	end

	local lastIndex = pb.lastIndex
	local playerIndex = pb.playerIndex

	local hasAutoGet = false
	if isFlight then
		--- 飞行状态默认自动获取
		hasAutoGet = true
	else
		hasAutoGet = recordFinishEventTypeMap[ModelFastDreamTrip.EVENT_TYPE_DIRECTREWARD]
	end

	local isSamePos = playerIndex == lastIndex

	self:SetDreamTripDiceCount(pb.diceCount)

	local notRefreshGrid = hasAutoGet
	if isSamePos then
		notRefreshGrid = false
	end

	if self._recordTime and Time.time - self._recordTime < 1 then
		notRefreshGrid = false
	end
	self._recordTime = Time.time
	--- 刷新所有地块数据
	FireEvent(EventNames.ON_FDT_REFRESH_EVENTINFO,{
		hasAutoGet = notRefreshGrid,
	})

	--- 事件完成通知
	FireEvent(EventNames.ON_FDT_EVENT_FINISH,recordFinishMap,pb,hasAutoGet)

	if isSamePos then
		printInfoNR2("梦境之旅：","旧位置和新位置一样，不处理")
		return
	end

	local isDoFlight = false
	if isFlight then
		isDoFlight = true
	elseif isFlightEnd then
		isDoFlight = true
	end

	if hasAutoGet and not self:CheckCurMapIsDice2() and not isDoFlight then
		hasAutoGet = false
	end
	local curIndex = self:GetDreamTripIndex()
	if hasAutoGet then
		printInfoNR2("梦境之旅：","hasAutoGet = true")
		self:DisposeHasAutoMove(pb,curIndex,{
			eventTypeFinishMap = recordFinishEventTypeMap,
			isFlight = isFlight,
			isFlightEnd = isFlightEnd,
		})
	else
		printInfoNR2("梦境之旅：","hasAutoGet = false")
		self:DisposeNormalMove(pb,curIndex,{
			isFlight = isFlight,
			isFlightEnd = isFlightEnd,
		})
	end
end


--- 好友联盟进度查询请求
function ModelFastDreamTrip:OnDreamTripScheduleResp(pb,ret)
	local friendInfoMap = {}
	local info = pb.info
	for i,v in ipairs(info) do
		local friendInfo = self:CreateDreamTripFriendInfo(v)
		friendInfoMap[friendInfo.index] = friendInfo
	end
	self._friendInfoMap = friendInfoMap
end
