function ModelFastDreamTrip:InitDreamTripInfo(pb)
	if not self._initLocalData then
		self:InitLocalRecordDTMapId()
		self._initLocalData = true
	end

	local beforeMapId = self:GetDreamTripMapId()
	local beforeMapLevel = self:GetDreamTripMapLevel()

	self._info = self:CreateDreamTripInfoDataByPb(pb)

	if beforeMapId and beforeMapLevel then
		local newMapId = self:GetDreamTripMapId()
		local newMapLevel = self:GetDreamTripMapLevel()
		local recordCurLv = self._recordDTMapIds[newMapId]
		if recordCurLv and recordCurLv < newMapLevel then
			self._recordDTMapUpStates[newMapId] = true
		else
			self._recordDTMapIds[newMapId] = recordCurLv
			self._recordDTMapUpStates[newMapId] = false
		end
	end
	self:CheckIsNeedReqFormation()
	FireEvent(EventNames.ON_FDT_REFRESH_EVENTINFO)
end

function ModelFastDreamTrip:DisposeNormalMove(pb,curIndex,extraInfo)
	local isFlight = extraInfo.isFlight
	local endInfo = pb.endInfo[1]
	local playerIndex = pb.playerIndex
	local isMove = false
	if playerIndex then
		if playerIndex ~= curIndex then
			isMove = true
		end
		self:SetDreamTripIndex(playerIndex)
	end
	local isAutoGet = false
	local isBomb = false
	--- 战斗是会退出梦境之旅
	local isNeedEnterMap = false
	if endInfo then
		local eventRefId = endInfo.eventRefId
		local eventType = self:GetDreamTripEventTypeByRefId(eventRefId)
		isAutoGet = eventType == ModelFastDreamTrip.EVENT_TYPE_DIRECTREWARD
		if eventType == ModelFastDreamTrip.EVENT_TYPE_MONSTER then
			local curMap = GF.GetCurMap()
			if curMap and curMap._mapClassName ~= "LFastDreamTripMap" then
				isNeedEnterMap = true
				isMove = false
			end
		elseif eventType == ModelFastDreamTrip.EVENT_TYPE_FORK then
			----- 岔路事件由 roll 协议完成
			--isMove = false
		end
		if eventType and eventType == ModelFastDreamTrip.EVENT_TYPE_BOMB then
			local eventInfo = self:GetDreamTripEventInfoByIdxAndId(endInfo.index,endInfo.eventId)
			if eventInfo then
				local boom_roll = self:GetDreamTripEventMoreInfoByKey(eventInfo,StructDreamTripEventInfo.BOOM_ROLL)
				if boom_roll and #boom_roll > 0 then
					isBomb = true
					local curIdx = eventInfo.index
					local boomIdx = boom_roll[1].subIndex
					local boomEndIdx
					if isMove then boomEndIdx = playerIndex end
					FireEvent(EventNames.ON_FDT_EVENT_BOMB,{
						curIdx = curIdx,
						boomIdx = boomIdx,
						boomEndIdx = boomEndIdx,
					})
				end
			end
		end
	end
	if not isBomb and isMove then
		local saveRollCb
		local lastInFork,lastInForkData = self:CheckCurPointInFork(curIndex)
		local curInFork,curInForkData = self:CheckCurPointInFork(playerIndex)
		local isInFork = lastInFork or curInFork
		if isInFork then
			printInfoNR2("梦境之旅：","OnDreamTripStartEventResp 岔路处理")
			local forkMoveState,moveFunc = self:_DisposeForkRoll(nil,{
				lastInFork = lastInFork,
				lastInForkData = lastInForkData,
				curInFork = curInFork,
				curInForkData = curInForkData,
				lastIndex = curIndex,
				moveEndIdx = playerIndex,
				isFlight = isFlight,
			},false)
			if forkMoveState then
				saveRollCb = moveFunc
			end
		end
		if not saveRollCb then
			--- 不是炸弹影响，前进
			local roll = playerIndex - curIndex
			if roll > 0 then
				saveRollCb = function()
					local rollNum = self._rollNum
					local isUseRoll = rollNum and rollNum > 0
					local lastIndex = curIndex
					printInfoNR2("梦境之旅：","OnDreamTripStartEventResp roll:"..roll)
					FireEvent(EventNames.ON_FDT_ROLL_NORMAL,{
						lastIndex = lastIndex,
						roll = rollNum or roll,
						moveEndIdx = playerIndex,
						isSwamp = 0,
						isFlight = isFlight,
						isFlightEnd = extraInfo.isFlightEnd,
					})
				end
			end
		end
		self._saveRollCb = saveRollCb
	end
	if not self:CheckIsWndShow() then
		self:CheckIsSaveRollCb()
	end
end

function ModelFastDreamTrip:DisposeHasAutoMove(pb,curIndex,extraInfo)
	local eventTypeFinishMap = extraInfo.eventTypeFinishMap
	local isFlight = extraInfo.isFlight
	local playerIndex = pb.playerIndex
	local isMove = false
	if playerIndex then
		if playerIndex ~= curIndex then
			isMove = true
		end
	end
	local isBomb = eventTypeFinishMap[ModelFastDreamTrip.EVENT_TYPE_BOMB]
	local isUpdatePos = true
	local isBattleEvent = eventTypeFinishMap[ModelFastDreamTrip.EVENT_TYPE_MONSTER]
	local notFlight = true
	local isFlightEnd = extraInfo.isFlightEnd
	if isFlightEnd then
		notFlight = false
	elseif isFlight then
		notFlight = false
	end
	if isBattleEvent and notFlight then
		isUpdatePos = false
	end
	local lastInFork,lastInForkData = self:CheckCurPointInFork(curIndex)
	local curInFork,curInForkData = self:CheckCurPointInFork(playerIndex)
	local isInFork = lastInFork or curInFork
	local saveRollCb
	if isInFork then
		local forkMoveState,moveFunc = self:_DisposeForkRoll(nil,{
			lastInFork = lastInFork,
			lastInForkData = lastInForkData,
			curInFork = curInFork,
			curInForkData = curInForkData,
			lastIndex = curIndex,
			moveEndIdx = playerIndex,
			playerIndex = playerIndex,
			isAutoGet = true,
			isFlight = isFlight,
		},false)
		if forkMoveState then
			printInfoNR2("梦境之旅：","OnDreamTripStartEventResp 岔路处理")
			saveRollCb = moveFunc
		end
	end
	local isUseRoll = false
	local rollNum
	if self._isRollRun then
		if self._rollNum and self._rollNum > 0 then
			isUseRoll = true
			rollNum = self._rollNum
		end
	end
	if isUpdatePos then
		if not saveRollCb then
			saveRollCb = function()
				local lastIndex = curIndex
				FireEvent(EventNames.ON_FDT_EVENT_MOVEPOS,{
					lastIndex = lastIndex,
					moveEndIdx = playerIndex,
					roll = rollNum or (playerIndex - curIndex),
					isSwamp = 0,
					isFlight = isFlight,
					isFlightEnd = isFlightEnd,
					moveFinishCb = function()
						self:SetDreamTripIndex(playerIndex)
					end
				})
			end
		end
		self._saveRollCb = saveRollCb
		if not self:CheckIsWndShow() then
			printInfoNR2("梦境之旅：","自动触发")
			self:CheckIsSaveRollCb()
		end
	else
		--- 不是炸弹影响，前进
		local roll = playerIndex - curIndex
		if not saveRollCb and roll > 0 then
			saveRollCb = function()
				printInfoNR2("梦境之旅：","OnDreamTripStartEventResp roll:"..roll)
				FireEvent(EventNames.ON_FDT_ROLL_NORMAL,{
					lastIndex = curIndex,
					roll = rollNum or roll,
					moveEndIdx = playerIndex,
					isSwamp = 0,
					isFlight = isFlight,
					isFlightEnd = isFlightEnd,
					moveFinishCb = function()
						self:SetDreamTripIndex(playerIndex)
					end
				})
			end
		end
		self._saveRollCb = saveRollCb
		printInfoNR2("梦境之旅：","手动触发，roll：" .. roll)
	end
end

function ModelFastDreamTrip:IsNeedShowRollAni()
	local isRollRun = self._isRollRun
	self._isRollRun = false
	self._rollNum = nil
	return isRollRun
end

function ModelFastDreamTrip:CheckIsWndShow()
	local wndNames = {
		"UIHopeEvent1",
		"UIHopeAnchor",
		"UIHopePray",
		"UIHopeMoney",
		"UIHopeForkroad",
		"UIHopeEventTip",
		"UIOrdinResult",
		"UIAward",
	}
	for i,v in ipairs(wndNames) do
		if gLGameUI:FindWndByName(v) then
			return true
		end
	end
	return false
end
