function ModelFastDreamTrip:GetDreamTripCurLv(mapId,playerLv)
	if not mapId or mapId < 1 then return 0 end
	local lvList = self:GetMapLevelListByMapId(mapId)
	local curIdx
	for i,v in ipairs(lvList) do
		if playerLv >= v.levelMin and playerLv <= v.levelMax then
			curIdx = i
			break
		end
	end
	if not curIdx then curIdx = 1 end
	return lvList[curIdx].level
end

