function ModelFastDreamTrip:TargetRewardShowEff(index,isEnd)
	if not index then return end

	---@type StructDreamTripGrid
	local grid = self:GetDreamTripGridByIndex(index)
	if not grid then return end

	local rewardList = {}
	---@param v StructDreamTripEventInfo
	for k,v in pairs(grid.eventMap) do
		if v.state == StructDreamTripGrid.FINISH and #v.reward > 0 then
			for idx,val in ipairs(v.reward) do
				if val.itemId == ModelItem.ITEM_DIAMOND then
					table.insert(rewardList,val)
				end
			end
		end
	end
	if #rewardList < 1 then return end

	FireEvent(EventNames.ON_DREAMTRIP_SHOWGET,{
		rewardList = rewardList,
		isNotTarget = true,
		index = index,
		isEnd = isEnd,
		autoGet = true,
	})
end

