function ModelFastDreamTrip:SetIsSkipOpen(isSkip,showTip)
	local skipOpen = self:GetConfigByKey("skipOpen")
	if skipOpen > gModelPlayer:GetPlayerLv() then
		if isSkip and showTip then
			local errorStr = string.replace(ccClientText(20480), skipOpen)
			GF.ShowMessage(errorStr)
		end
		return false
	end

	LPlayerPrefs.SetDreamTripSkipB(isSkip)
	return isSkip
end

function ModelFastDreamTrip:GetIsSkipOpen()
	local skipOpen = GameTable.SailingConfigRef["skipOpen"]
	if skipOpen > gModelPlayer:GetPlayerLv() then
		return false
	end

	local isCheck = toboolean(LPlayerPrefs.dreamTripSkipB) or false
	return isCheck
end

function ModelFastDreamTrip:CheckIsOpenDay(showTips)
