--- 是否已经打开过结算界面
function ModelFastDreamTrip:CheckIsEndPointFinish()
	local info = self:GetDreamTripInfo()
	if not info then return end

	local state = info:CheckIsEndPointFinish()
	if not state then
		if LOG_INFO_ENABLED then
			printInfoNR2("梦境之旅 终点检测","终点未完成")
		end
		return
	end

	local refreshTime = info.refreshTime
	if refreshTime and refreshTime > 0 then
		--- 完成终点事件且处于本期玩法开放的首次打开玩法时弹出
		local recordDTRefresTime = tonumber(LPlayerPrefs.recordDTRefresTime)
		if refreshTime > recordDTRefresTime then
			GF.OpenWnd("UIHopeSowAward")
			LPlayerPrefs.SetRecordDTRefresTime(tonumber(refreshTime))
			return true
		else
			if LOG_INFO_ENABLED then
				printInfoNR2("梦境之旅 终点检测","记录：refreshTime = " .. refreshTime .. ",recordDTRefresTime = " .. recordDTRefresTime)
			end
		end
	else
		if LOG_INFO_ENABLED then
			printInfoNR2("梦境之旅 终点检测","没有 refreshTime")
		end
	end
end

