function ModelFastDreamTrip:CheckCanMoveNum(index)
	local moveNum = 0
	printInfoNR2("梦境之旅：","ModelFastDreamTrip.TYPE_MAP_DICE_2 index = " .. index)
	for i = index,index + 6 do
		---@type StructDreamTripGrid
		local gridInfo = self:GetDreamTripGridByIndex(i)
		if not gridInfo then break end
		if gridInfo:CheckGridIsFinish() then
			printInfoNR2("梦境之旅：","gridInfo:CheckGridIsFinish() = " .. gridInfo.index)
			moveNum = moveNum + 1
		else
			break
		end
	end
	return moveNum
end

