---@return table<StructDreamTripEventInfo>
function ModelFastDreamTrip:GetCurMapForkDatas()
	local successIndexKey = self:GetDreamTripSuccessIndexKey()
	if not successIndexKey then return {} end

	local forks = {}
	---@param k string 事件id
	---@param v StructDreamTripEventInfo 事件数据
	for k,v in pairs(successIndexKey) do
		if v.eventType == ModelFastDreamTrip.EVENT_TYPE_FORK then
			local moreInfo = v.moreInfo[StructDreamTripEventInfo.BYROAD_CHOSE]
			if moreInfo and #moreInfo > 0 then
				local forkSelData = moreInfo[1]
				table.insert(forks,{
					eventId = v.eventId,
					index = v.index,
					eventRefId = v.eventRefId,
					eventType = v.eventType,
					direType = forkSelData.direType,
					gridIndex = forkSelData.gridIndex,
					gridEndIndex = forkSelData.gridEndIndex,
					gridLinkIndex = forkSelData.gridLinkIndex,
				})
			end
		end
	end
	if #forks > 0 then
		table.sort(forks,function(a, b) return a.index < b.index end)
	end
	return forks
end

