--- 当前的位置是否在岔路里
function ModelFastDreamTrip:CheckCurPointInFork(point)
	local forks = self:GetCurMapForkDatas()
	if #forks < 1 then return false end
	for i,v in ipairs(forks) do
		local mapData = self:GetMapPointDatasByEventRefId(v.eventRefId)
		if mapData and mapData[point] then
			return true,v
		end
	end
	return false
end

