function ModelFastDreamTrip:CheckIsEventType(index,eventType,eventTypeMap)
	---@type StructDreamTripGrid
	local gridInfo = self:GetDreamTripGridByIndex(index)
	if not gridInfo then return false,nil end
	---@param v StructDreamTripEventInfo
	for k,v in pairs(gridInfo.eventMap) do
		if eventTypeMap and eventTypeMap[v.eventType] then
			return true ,v
		else
			if v.eventType == eventType then
				return true,v
			end
		end
	end
	return false,nil
end

