function ModelFastDreamTrip:GetCurPosFlip()
	local nextIdx
	local index = self:GetDreamTripIndex()
	local isFork,eventInfo = self:CheckIndexEventIsFork(index)
	if isFork then
		--- 当前在岔路口
		if eventInfo:CheckIsFinishEvent() then
			local moreInfo = eventInfo.moreInfo[StructDreamTripEventInfo.BYROAD_CHOSE]
			if moreInfo and #moreInfo > 0 then
				local forkSelData = moreInfo[1]
				nextIdx = forkSelData.gridIndex
			end
		else
			local parameterList = self:GetForkroadParameter(eventInfo.eventRefId)
			if parameterList and #parameterList > 0 then
				local first = parameterList[1]
				nextIdx = first.gridStartIndex
			end
		end
	else
		if self:CheckCurIndexInFork(index) then
			nextIdx = index + 1
			if not self:CheckCurIndexInFork(nextIdx) then
				local mapId = self:GetDreamTripMapId()
				if self._paramEventPointByEventRefIdMap[mapId] then
					local eventRefId = self._paramEventPointByEventRefIdMap[mapId][index]
					if eventRefId then
						local parameterList = self:GetForkroadParameter(eventRefId)
						if parameterList and #parameterList > 0 then
							local first = parameterList[1]
							nextIdx = first.gridLinkIndex
						end
					end
				end
			end
		end
	end
	if not nextIdx then
		nextIdx = index + 1
	end
	local mapGameId = self:GetDreamTripMapGameId()
	local curPos = self:GetMapDreamTripGridPos(mapGameId,index)
	local nextPos = self:GetMapDreamTripGridPos(mapGameId,nextIdx)
	return nextPos.x <= curPos.x
end

function ModelFastDreamTrip:GetCurPosFlightDice()
	local nextIdx
	local index = self:GetDreamTripIndex()
	local isFork,eventInfo = self:CheckIndexEventIsFork(index)
	if isFork then
		--- 当前在岔路口
		if eventInfo:CheckIsFinishEvent() then
			local moreInfo = eventInfo.moreInfo[StructDreamTripEventInfo.BYROAD_CHOSE]
			if moreInfo and #moreInfo > 0 then
				local forkSelData = moreInfo[1]
				nextIdx = forkSelData.gridIndex
			end
		else
			local parameterList = self:GetForkroadParameter(eventInfo.eventRefId)
			if parameterList and #parameterList > 0 then
				local first = parameterList[1]
				nextIdx = first.gridStartIndex
			end
		end
	else
		if self:CheckCurIndexInFork(index) then
			nextIdx = index + 1
			if not self:CheckCurIndexInFork(nextIdx) then
				local mapId = self:GetDreamTripMapId()
				if self._paramEventPointByEventRefIdMap[mapId] then
					local eventRefId = self._paramEventPointByEventRefIdMap[mapId][index]
					if eventRefId then
						local parameterList = self:GetForkroadParameter(eventRefId)
						if parameterList and #parameterList > 0 then
							local first = parameterList[1]
							nextIdx = first.gridLinkIndex
						end
					end
				end
			end
		end
	end
	if not nextIdx then
		nextIdx = index + 1
	end
	local mapGameId = self:GetDreamTripMapGameId()
	local curPos = self:GetMapDreamTripGridPos(mapGameId,index)
	local nextPos = self:GetMapDreamTripGridPos(mapGameId,nextIdx)
	local bLeft = nextPos.x <= curPos.x
	local bDown = nextPos.y <= curPos.y
	local status
	if bLeft then
		status = bDown and 2 or 3
	else
		status = bDown and 1 or 4
	end
	return status
end
