---@param eventInfo StructDreamTripEventInfo
function ModelFastDreamTrip:OpenEventUI(eventInfo,params)
	if not eventInfo then return end
	params = params or {}
	local plot = self:GetDreamTripEventPlotByRefId(eventInfo.eventRefId)
	if LOG_INFO_ENABLED then
		printInfoNR2("打印事件剧情:",string.replace("#a1# 配置的剧情:#a2#",eventInfo.eventRefId,plot or 0))
	end
	if plot and plot > 0 then
		gModelPlot:StartPlotAndCallback(plot,function()
			self:_OpenEventUI(eventInfo,params)
		end)
	else
		self:_OpenEventUI(eventInfo,params)
	end
end

---@param eventInfo StructDreamTripEventInfo
function ModelFastDreamTrip:_OpenEventUI(eventInfo,params)
	if not eventInfo then return end
	params = params or {}
	local eventType = eventInfo.eventType
	if eventType == ModelFastDreamTrip.EVENT_TYPE_MONSTER then
		--- 怪物事件
		self:_OpenMonsterUI(eventInfo,params)
	elseif eventType == ModelFastDreamTrip.EVENT_TYPE_BOMB then
		--- 炸弹事件
		params.trigger = true
		self:OpenEventTips(eventInfo,params)
	elseif eventType == ModelFastDreamTrip.EVENT_TYPE_END then
		--- 终点事件
		self:_OpenEndUI(eventInfo,params)
	elseif eventType == ModelFastDreamTrip.EVENT_TYPE_DIRECTREWARD then
		--- 直接获得奖励宝箱事件
		self:OnDreamTripStartEventReq(eventInfo.eventId)
	elseif eventType == ModelFastDreamTrip.EVENT_TYPE_DROPANCHOR then
		--- 抛锚事件
		self:_OpenDreamTripCommonTips(eventInfo,params)
	elseif eventType == ModelFastDreamTrip.EVENT_TYPE_PRAY then
		--- 祈祷事件
		self:_OpenDreamTripCommonTips(eventInfo,params)
	elseif eventType == ModelFastDreamTrip.EVENT_TYPE_MONEYTREE then
		--- 摇钱树事件
		self:_OpenMoneyTree(eventInfo,params)
	elseif eventType == ModelFastDreamTrip.EVENT_TYPE_FORK then
		--- 岔路事件
		self:_OpenFork(eventInfo,params)
	elseif eventType == ModelFastDreamTrip.EVENT_TYPE_FLIGHT then
		--- 飞行事件
		self:_OpenDreamTripCommonTips(eventInfo,params)
	end
end

---@param eventInfo StructDreamTripEventInfo
function ModelFastDreamTrip:_OpenMonsterUI(eventInfo,params)
	GF.OpenWnd("UIHopeEvent1",{eventInfo = eventInfo,gameParams = params})
