---@param eventInfo StructDreamTripEventInfo
function ModelFastDreamTrip:_OpenEndUI(eventInfo,params)
	local ref = self:GetDreamTripEventRefByRefId(eventInfo.eventRefId)
	if ref and not string.isempty(ref.monster) then
		---终点事件特殊处理，如果是配置怪物，则默认打开怪物战斗事件
		self:_OpenMonsterUI(eventInfo,params)
		return
	end
	FireEvent(EventNames.ON_FDT_FORK_ENDFUNC)
end

